/**
 * Quote Key Metrics Block
 *
 * Displays key metrics cards for quotation detail page using Antd components.
 * Metrics:
 * - Total Amount
 * - Discount Amount
 * - Items Count
 * - Days Until Expiry
 *
 * Table: nb_crm_quotations
 * Fields: total_amount, discount_amount, valid_until, currency
 */

const { Row, Col, Card, Statistic, Typography } = ctx.antd;
const { Text } = Typography;

// Currency symbols
const CURRENCY_SYMBOLS = {
  CNY: '¥',
  USD: '$',
  EUR: '€',
  GBP: '£',
};

const formatAmount = (amount) => {
  return (amount || 0).toLocaleString('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
};

const QuoteMetrics = () => {
  const record = ctx.record || ctx.popup?.record || {};
  const totalAmount = record.total_amount || 0;
  const discountAmount = record.discount_amount || 0;
  const currency = record.currency || 'CNY';
  const symbol = CURRENCY_SYMBOLS[currency] || currency;
  const validUntil = record.valid_until;

  // Count items from relation or default to 0
  const itemsCount = record.items?.length || record.quote_items?.length || 0;

  // Calculate days until expiry
  let daysLeft = '-';
  let daysColor = '#52c41a';
  if (validUntil) {
    const now = new Date();
    const expiryDate = new Date(validUntil);
    const diffDays = Math.ceil((expiryDate - now) / (1000 * 60 * 60 * 24));
    if (diffDays < 0) {
      daysLeft = 'Expired';
      daysColor = '#ff4d4f';
    } else {
      daysLeft = diffDays;
      daysColor = diffDays <= 7 ? '#faad14' : '#52c41a';
    }
  }

  const metrics = [
    {
      label: 'Total Amount',
      value: `${symbol}${formatAmount(totalAmount)}`,
      color: '#722ed1',
    },
    {
      label: 'Discount',
      value: `${symbol}${formatAmount(discountAmount)}`,
      color: '#eb2f96',
    },
    {
      label: 'Items',
      value: itemsCount,
      color: '#1890ff',
    },
    {
      label: 'Days Left',
      value: daysLeft,
      color: daysColor,
    },
  ];

  return (
    <Row gutter={16} style={{ padding: 16 }}>
      {metrics.map((metric, index) => (
        <Col key={index} span={6}>
          <Card
            size="small"
            style={{ textAlign: 'center', backgroundColor: '#fff', border: '1px solid #f0f0f0' }}
            styles={{ body: { padding: 16 } }}
          >
            <Statistic
              title={<Text type="secondary" style={{ fontSize: 12 }}>{metric.label}</Text>}
              value={metric.value}
              valueStyle={{ color: metric.color, fontSize: 20, fontWeight: 600 }}
            />
          </Card>
        </Col>
      ))}
    </Row>
  );
};

ctx.render(<QuoteMetrics />);

/**
 * Quotation Status Flow Block
 * Table: nb_crm_quotations
 *
 * Displays quotation status with clickable steps to switch status.
 * Status flow: draft → pending_approval → approved → sent → accepted
 * Terminal states: rejected, expired
 *
 * Data source: ctx.record (popup/drawer detail page)
 */

const { React } = ctx;
const { useState, useEffect, useMemo } = React;
const { Steps, Tag, Space, message, Spin, Modal } = ctx.antd;
// Theme detection
const algorithm = ctx.antdConfig?.theme?.algorithm;
const darkAlgo = ctx.antd.theme.darkAlgorithm;
const isDark = Array.isArray(algorithm)
  ? algorithm.some(fn => fn === darkAlgo)
  : algorithm === darkAlgo;
const T = ctx.themeToken || {};

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.quotes', ...opts });

// ==================== Config ====================

const STATUS_FLOW = [
  { code: 'draft', label: t('Draft'), color: 'default' },
  { code: 'pending_approval', label: t('Pending Approval'), color: 'orange' },
  { code: 'approved', label: t('Approved'), color: 'blue' },
  { code: 'sent', label: t('Sent'), color: 'cyan' },
  { code: 'accepted', label: t('Accepted'), color: 'green', isWon: true },
];

const TERMINAL_STATUSES = {
  rejected: { label: t('Rejected'), color: 'red', isLost: true },
  expired: { label: t('Expired'), color: 'default', isLost: true },
};

// ==================== Helper Functions ====================

function getStatusIndex(statusCode) {
  return STATUS_FLOW.findIndex((s) => s.code === statusCode);
}

function getStepsStatus(status, isWon, isLost) {
  if (isWon) return 'finish';
  if (isLost) return 'error';
  return 'process';
}

// ==================== Main Component ====================

const QuotationStatusFlow = () => {
  const record = ctx.record || ctx.popup?.record || {};
  const initialStatus = record.status || 'draft';
  const recordId = record.id;

  const [updating, setUpdating] = useState(false);
  const [currentStatus, setCurrentStatus] = useState(initialStatus);

  // Sync with record changes
  useEffect(() => {
    setCurrentStatus(record.status || 'draft');
  }, [record.status]);

  // Current status info
  const currentStatusInfo = useMemo(() => {
    const found = STATUS_FLOW.find(s => s.code === currentStatus);
    if (found) return found;
    if (TERMINAL_STATUSES[currentStatus]) {
      return { code: currentStatus, ...TERMINAL_STATUSES[currentStatus] };
    }
    return STATUS_FLOW[0];
  }, [currentStatus]);

  const isTerminal = currentStatusInfo.isWon || currentStatusInfo.isLost;
  const currentIndex = getStatusIndex(currentStatus);

  // Handle status click
  const handleStepClick = async (stepIndex) => {
    if (isTerminal || !recordId || updating) return;

    const targetStatus = STATUS_FLOW[stepIndex];
    if (!targetStatus || targetStatus.code === currentStatus) return;

    // Confirm if moving to terminal status
    if (targetStatus.isWon) {
      Modal.confirm({
        title: t('Mark as "{{label}}"?', { label: targetStatus.label }),
        content: t('This will mark the quotation as accepted by customer.'),
        okText: t('Confirm'),
        cancelText: t('Cancel'),
        onOk: () => updateStatus(targetStatus),
      });
      return;
    }

    await updateStatus(targetStatus);
  };

  // Handle terminal status (rejected/expired)
  const handleTerminalClick = (terminalCode) => {
    if (isTerminal || !recordId || updating) return;

    const terminalInfo = TERMINAL_STATUSES[terminalCode];
    Modal.confirm({
      title: t('Mark as "{{label}}"?', { label: terminalInfo.label }),
      content: terminalCode === 'rejected'
        ? 'This will mark the quotation as rejected by customer.'
        : 'This will mark the quotation as expired.',
      okText: t('Confirm'),
      cancelText: t('Cancel'),
      okButtonProps: { danger: true },
      onOk: () => updateStatus({ code: terminalCode, ...terminalInfo }),
    });
  };

  const updateStatus = async (targetStatus) => {
    setUpdating(true);
    try {
      const updateData = {
        status: targetStatus.code,
      };

      // Add timestamp for certain statuses
      if (targetStatus.code === 'sent') {
        updateData.sent_at = new Date().toISOString();
      } else if (targetStatus.code === 'accepted') {
        updateData.accepted_at = new Date().toISOString();
      }

      await ctx.api.request({
        url: `nb_crm_quotations:update`,
        method: 'POST',
        params: { filterByTk: recordId },
        data: updateData,
      });

      // Immediately update local state for instant feedback
      setCurrentStatus(targetStatus.code);

      message.success(`Status updated to "${targetStatus.label}"`);

      // Refresh record
      if (ctx.refresh) {
        ctx.refresh();
      } else if (ctx.service?.refresh) {
        ctx.service.refresh();
      }
    } catch (error) {
      console.error('Failed to update status:', error);
      message.error(t('Failed to update status'));
    } finally {
      setUpdating(false);
    }
  };

  // Build display steps
  const displayIndex = currentIndex >= 0 ? currentIndex : STATUS_FLOW.length;

  const stepsItems = STATUS_FLOW.map((status, index) => {
    let stepStatus = 'wait';

    if (isTerminal && currentStatusInfo.isLost) {
      // Show progress up to where it was before terminal
      stepStatus = index <= displayIndex ? 'finish' : 'wait';
    } else if (index < displayIndex) {
      stepStatus = 'finish';
    } else if (index === displayIndex) {
      stepStatus = getStepsStatus(status, status.isWon, false);
    }

    const isClickable = !isTerminal && status.code !== currentStatus;

    return {
      title: (
        <Space size={4}>
          <span>{status.label}</span>
          {status.code === currentStatus && (
            <Tag color="blue" style={{ fontSize: 10 }}>{t('Current')}</Tag>
          )}
        </Space>
      ),
      status: stepStatus,
      style: isClickable ? { cursor: 'pointer' } : {},
    };
  });

  // Add terminal status if current
  if (TERMINAL_STATUSES[currentStatus]) {
    stepsItems.push({
      title: (
        <Space size={4}>
          <span>{TERMINAL_STATUSES[currentStatus].label}</span>
          <Tag color="red" style={{ fontSize: 10 }}>{t('Current')}</Tag>
        </Space>
      ),
      status: 'error',
    });
  }

  return (
    <div style={{ position: 'relative' }}>
      {updating && (
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: isDark ? 'rgba(0,0,0,0.5)' : 'rgba(255,255,255,0.7)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 10,
        }}>
          <Spin size="small" />
        </div>
      )}

      <Steps
        size="small"
        current={displayIndex}
        items={stepsItems}
        onChange={handleStepClick}
      />

      {/* Terminal actions */}
      {!isTerminal && (
        <div style={{ marginTop: 12, display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
          <Tag
            color="red"
            style={{ cursor: 'pointer' }}
            onClick={() => handleTerminalClick('rejected')}
          >{t('Mark as Rejected')}</Tag>
          <Tag
            color="default"
            style={{ cursor: 'pointer' }}
            onClick={() => handleTerminalClick('expired')}
          >{t('Mark as Expired')}</Tag>
        </div>
      )}
    </div>
  );
};

ctx.render(<QuotationStatusFlow />);

/**
 * Opportunity Stage Flow Block
 * Table: nb_crm_opportunities
 *
 * Displays current opportunity stage with clickable steps to switch stages.
 * Stages are fetched from nb_crm_opportunity_stages table dynamically.
 *
 * Data source: ctx.record (popup/drawer detail page)
 */

const { React } = ctx;
const { useState, useEffect, useMemo } = React;
const { Steps, Tag, Space, message, Spin, Modal } = ctx.antd;

// Theme detection
const algorithm = ctx.antdConfig?.theme?.algorithm;
const darkAlgo = ctx.antd.theme.darkAlgorithm;
const isDark = Array.isArray(algorithm)
  ? algorithm.some(fn => fn === darkAlgo)
  : algorithm === darkAlgo;
const T = ctx.themeToken || {};

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.pipeline', ...opts });

// ==================== Config ====================

// Fallback stages if API fails (matching fields enum)
const FALLBACK_STAGES = [
  { code: 'prospecting', name: 'Initial Contact', sort_order: 1, win_probability: 10, is_won: false, is_lost: false },
  { code: 'analysis', name: 'Needs Analysis', sort_order: 2, win_probability: 30, is_won: false, is_lost: false },
  { code: 'proposal', name: 'Proposal', sort_order: 3, win_probability: 60, is_won: false, is_lost: false },
  { code: 'negotiation', name: 'Negotiation', sort_order: 4, win_probability: 80, is_won: false, is_lost: false },
  { code: 'won', name: 'Won', sort_order: 5, win_probability: 100, is_won: true, is_lost: false },
  { code: 'lost', name: 'Lost', sort_order: 6, win_probability: 0, is_won: false, is_lost: true },
];

// ==================== Helper Functions ====================

function getStageIndex(stages, stageCode) {
  return stages.findIndex((s) => s.code === stageCode);
}

function getStepsStatus(stage, isWon, isLost) {
  if (isWon) return 'finish';
  if (isLost) return 'error';
  return 'process';
}

// ==================== Main Component ====================

const OpportunityStageFlow = () => {
  const record = ctx.record || ctx.popup?.record || {};
  const initialStage = record.stage || 'prospecting';
  const recordId = record.id;
  const spaceName = ctx.space?.selected;

  const [stages, setStages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [updating, setUpdating] = useState(false);
  const [currentStage, setCurrentStage] = useState(initialStage);

  // Sync with record changes
  useEffect(() => {
    setCurrentStage(record.stage || 'prospecting');
  }, [record.stage]);

  // Fetch stages from database
  useEffect(() => {
    const fetchStages = async () => {
      if (!ctx.api) {
        setStages(FALLBACK_STAGES);
        setLoading(false);
        return;
      }

      try {
        const params = {
          filter: { is_active: true },
          sort: ['sort_order'],
          fields: ['id', 'code', 'name', 'sort_order', 'win_probability', 'is_won', 'is_lost', 'color'],
        };

        // Add space filter if available
        if (spaceName) {
          params.filter.spaceName = spaceName;
        }

        const res = await ctx.api.request({
          url: 'nb_crm_opportunity_stages:list',
          method: 'GET',
          params,
        });

        const stagesData = res?.data?.data || [];
        setStages(stagesData.length > 0 ? stagesData : FALLBACK_STAGES);
      } catch (error) {
        console.error('Failed to fetch stages:', error);
        setStages(FALLBACK_STAGES);
      } finally {
        setLoading(false);
      }
    };

    fetchStages();
  }, [spaceName]);

  // Current stage info
  const currentStageInfo = useMemo(() => {
    return stages.find(s => s.code === currentStage) || {};
  }, [stages, currentStage]);

  const isTerminal = currentStageInfo.is_won || currentStageInfo.is_lost;
  const currentIndex = getStageIndex(stages, currentStage);

  // Handle stage click
  const handleStepClick = async (stepIndex) => {
    if (isTerminal || !recordId || updating) return;

    const targetStage = stages[stepIndex];
    if (!targetStage || targetStage.code === currentStage) return;

    // Confirm if moving to terminal stage
    if (targetStage.is_won || targetStage.is_lost) {
      Modal.confirm({
        title: t('Move to "{{name}}"?', { name: targetStage.name }),
        content: targetStage.is_won
          ? 'This will mark the opportunity as Won. This action may trigger related workflows.'
          : 'This will mark the opportunity as Lost. Please ensure you have recorded the reason.',
        okText: t('Confirm'),
        cancelText: t('Cancel'),
        onOk: () => updateStage(targetStage),
      });
      return;
    }

    await updateStage(targetStage);
  };

  const updateStage = async (targetStage) => {
    setUpdating(true);
    try {
      await ctx.api.request({
        url: `nb_crm_opportunities:update`,
        method: 'POST',
        params: { filterByTk: recordId },
        data: {
          stage: targetStage.code,
          stage_sort: targetStage.sort_order,
          stage_entered_at: new Date().toISOString(),
        },
      });

      // Immediately update local state for instant feedback
      setCurrentStage(targetStage.code);

      message.success(`Stage updated to "${targetStage.name}"`);

      // Also try to refresh the record for other components
      if (ctx.refresh) {
        ctx.refresh();
      } else if (ctx.service?.refresh) {
        ctx.service.refresh();
      }
    } catch (error) {
      console.error('Failed to update stage:', error);
      message.error(t('Failed to update stage'));
    } finally {
      setUpdating(false);
    }
  };

  if (loading) {
    return (
      <Space style={{ padding: 16, justifyContent: 'center', width: '100%' }}>
        <Spin size="small" />
      </Space>
    );
  }

  // Separate won and lost stages from progress stages
  const progressStages = stages.filter(s => !s.is_won && !s.is_lost);
  const wonStage = stages.find(s => s.is_won);
  const lostStage = stages.find(s => s.is_lost);

  // Build display stages: progress stages + won + lost (like leads: new -> working -> converted -> lost)
  const displayStages = [...progressStages];
  if (wonStage) displayStages.push(wonStage);
  if (lostStage) displayStages.push(lostStage);

  // Calculate current display index
  let displayIndex = displayStages.findIndex(s => s.code === currentStage);
  if (displayIndex < 0) displayIndex = 0;

  // Build steps items
  const stepsItems = displayStages.map((stage, index) => {
    let status = 'wait';

    if (index < displayIndex) {
      status = 'finish';
    } else if (index === displayIndex) {
      status = getStepsStatus(stage, stage.is_won, stage.is_lost);
    }

    const isClickable = !isTerminal && stage.code !== currentStage;

    return {
      title: (
        <Space size={4}>
          <span>{stage.name}</span>
          {stage.code === currentStage && (
            <Tag color="blue" style={{ fontSize: 10 }}>{t('Current')}</Tag>
          )}
        </Space>
      ),
      description: stage.win_probability != null ? `${stage.win_probability}%` : undefined,
      status,
      onClick: isClickable ? () => handleStepClick(stages.indexOf(stage)) : undefined,
      style: isClickable ? { cursor: 'pointer' } : {},
    };
  });

  return (
    <div style={{ position: 'relative' }}>
      {updating && (
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: isDark ? 'rgba(0,0,0,0.45)' : 'rgba(255,255,255,0.7)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 10,
        }}>
          <Spin size="small" />
        </div>
      )}

      <Steps
        size="small"
        current={displayIndex}
        items={stepsItems}
      />
    </div>
  );
};

ctx.render(<OpportunityStageFlow />);

/**
 * Quote Status Flow Block
 * Table: nb_crm_quotations (related to opportunity)
 *
 * Displays current quote's status flow visualization
 * Status flow from fields enum: draft → pending_approval → approved → sent → accepted/rejected
 *
 * Data source: API fetch latest quotation by opportunity_id
 */

const { React } = ctx;
const { useState, useEffect } = React;
const { Space, Typography, Spin, Empty } = ctx.antd;
const { Text } = Typography;

// Theme detection
const algorithm = ctx.antdConfig?.theme?.algorithm;
const darkAlgo = ctx.antd.theme.darkAlgorithm;
const isDark = Array.isArray(algorithm)
  ? algorithm.some(fn => fn === darkAlgo)
  : algorithm === darkAlgo;
const T = ctx.themeToken || {};

// i18n
const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.pipeline', ...opts });

// ==================== Config ====================

// Status flow order (matches fields enum)
const STATUS_FLOW = [
  { key: 'draft', label: t('Draft'), color: 'default' },
  { key: 'pending_approval', label: t('Pending Approval'), color: 'orange' },
  { key: 'approved', label: t('Approved'), color: 'blue' },
  { key: 'sent', label: t('Sent'), color: 'cyan' },
