    fontSize: 14,
    fontWeight: 600,
  },
  flow: {
    display: 'flex',
    alignItems: 'center',
    flexWrap: 'wrap',
    gap: 4,
  },
  node: (status) => ({
    padding: '6px 12px',
    borderRadius: 16,
    fontSize: 12,
    fontWeight: 500,
    background: status === 'completed' ? (isDark ? 'rgba(34,197,94,0.15)' : '#f0fdf4') :
                status === 'current' ? (isDark ? 'rgba(59,130,246,0.15)' : '#eff6ff') :
                status === 'rejected' ? (isDark ? 'rgba(239,68,68,0.15)' : '#fef2f2') :
                status === 'expired' ? (T.colorBgLayout || '#f5f5f5') : (T.colorBgLayout || '#f5f5f5'),
    color: status === 'completed' ? (T.colorSuccess || '#22c55e') :
           status === 'current' ? '#3b82f6' :
           status === 'rejected' ? (T.colorError || '#ef4444') :
           status === 'expired' ? (T.colorTextTertiary || '#9ca3af') : (T.colorTextTertiary || '#9ca3af'),
    border: status === 'current' ? '2px solid #3b82f6' : '1px solid transparent',
  }),
  arrow: (completed) => ({
    color: completed ? (T.colorSuccess || '#22c55e') : (T.colorBorderSecondary || '#d9d9d9'),
    fontSize: 14,
    margin: '0 2px',
  }),
  versionTag: {
    marginLeft: 8,
    fontSize: 12,
    color: '#6366f1',
    fontWeight: 600,
  },
};

// ==================== Helper Functions ====================

function getStatusIndex(status) {
  return STATUS_FLOW.findIndex(s => s.key === status);
}

// ==================== Main Component ====================

const QuoteStatusFlow = () => {
  const record = ctx.record || ctx.popup?.record || {};
  const opportunityId = record.id;

  const [quote, setQuote] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!opportunityId || !ctx.api) {
      setLoading(false);
      return;
    }

    const fetchLatestQuote = async () => {
      try {
        const res = await ctx.api.request({
          url: 'nb_crm_quotations:list',
          method: 'GET',
          params: {
            filter: { opportunity_id: opportunityId },
            sort: ['-version'],
            fields: ['id', 'version', 'status'],
            pageSize: 1,
          },
        });
        const quotes = res?.data?.data || [];
        setQuote(quotes[0] || null);
      } catch (error) {
        console.error('Failed to fetch quote:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchLatestQuote();
  }, [opportunityId]);

  if (loading) {
    return (
      <div style={styles.container}>
        <Space style={{ width: '100%', justifyContent: 'center', padding: 24 }}>
          <Spin size="small" />
        </Space>
      </div>
    );
  }

  if (!quote) {
    return (
      <div style={styles.container}>
        <div style={styles.title}>
          <span>{t('Quote Status Flow')}</span>
        </div>
        <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="No quotes yet" />
      </div>
    );
  }

  const currentStatus = quote.status || 'draft';
  const isTerminal = !!TERMINAL_STATUSES[currentStatus];
  const currentIndex = getStatusIndex(currentStatus);

  // Build flow items
  const flowItems = STATUS_FLOW.map((item, index) => {
    let nodeStatus = 'pending';
    if (isTerminal) {
      // Show completed up to where it stopped, then terminal
      const terminalIndex = getStatusIndex(currentStatus);
      if (terminalIndex >= 0) {
        if (index < terminalIndex) nodeStatus = 'completed';
        else if (index === terminalIndex) nodeStatus = currentStatus;
      } else {
        // Terminal status not in flow, show all as completed before terminal
        nodeStatus = 'completed';
      }
    } else if (index < currentIndex) {
      nodeStatus = 'completed';
    } else if (index === currentIndex) {
      nodeStatus = 'current';
    }
    return { ...item, nodeStatus };
  });

  return (
    <div style={styles.container}>
      <div style={styles.title}>
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/>
        </svg>
        <span>{t('Quote Status Flow')}</span>
        <span style={styles.versionTag}>(V{quote.version || 1})</span>
      </div>

      <div style={styles.flow}>
        {flowItems.map((item, index) => (
          <React.Fragment key={item.key}>
            <span style={styles.node(item.nodeStatus)}>
              {item.nodeStatus === 'completed' && '✓ '}
              {item.nodeStatus === 'current' && '● '}
              {item.label}
            </span>
            {index < flowItems.length - 1 && (
              <span style={styles.arrow(item.nodeStatus === 'completed')}>→</span>
            )}
          </React.Fragment>
        ))}
        {isTerminal && (
          <>
            <span style={styles.arrow(false)}>→</span>
            <span style={styles.node(currentStatus)}>
              {TERMINAL_STATUSES[currentStatus].label}
            </span>
          </>
        )}
      </div>
    </div>
  );
};

ctx.render(<QuoteStatusFlow />);

// Get time fields: Prioritize the last interaction date
const lastInteractionDate = ctx.record?.relatedMessageLatestDate;
const date = ctx.record?.date;
const createdAt = ctx.record?.createdAt;
const updatedAt = ctx.record?.updatedAt;

// Determine display date
const displayDate = lastInteractionDate || date || updatedAt || createdAt;

// Utility function: Calculate relative time
const formatRelativeTime = (date) => {
  if (!date) return 'No Date';

  const now = new Date();
  const target = new Date(date);
  const diffMs = now - target;

  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);
  const diffHour = Math.floor(diffMin / 60);
  const diffDay = Math.floor(diffHour / 24);

  // Helper for pluralization (e.g., "1 day" vs "2 days")
  const pluralize = (num, unit) => `${num} ${unit}${num !== 1 ? 's' : ''} ago`;

  if (diffSec < 60) return 'Just now';
  if (diffMin < 60) return pluralize(diffMin, 'minute');
  if (diffHour < 24) return pluralize(diffHour, 'hour');
  if (diffDay === 1) return 'Yesterday';
  if (diffDay < 7) return pluralize(diffDay, 'day');
  if (diffDay < 30) return pluralize(Math.floor(diffDay / 7), 'week');
  if (diffDay < 365) return pluralize(Math.floor(diffDay / 30), 'month');

  return pluralize(Math.floor(diffDay / 365), 'year');
};

// Format date string for tooltip
const formatFullTime = (date) => {
  if (!date) return 'Unknown Time';
  const d = new Date(date);
  return d.toLocaleString('en-US'); // Formatting for US English locale
};

// Set color based on date recency
const getStyleByDate = (date) => {
  if (!date) return { color: '#bfbfbf' };

  const diff = (new Date() - new Date(date)) / (1000 * 60 * 60 * 24); // Difference in days

  if (diff < 1) {
    return { color: '#1677ff' }; // Blue for today
  } else if (diff < 7) {
    return { color: '#fa8c16' }; // Orange for within a week
  } else {
    return { color: '#8c8c8c' }; // Grey for older than a week
  }
};

const style = getStyleByDate(displayDate);
const relativeText = formatRelativeTime(displayDate);
const tooltipText = formatFullTime(displayDate);

ctx.element.innerHTML = `
  <div style="
    display: inline-block;
    font-size: 13px;
    color: ${style.color};
    background: transparent;
    padding: 2px 6px;
    border-radius: 3px;
    transition: all 0.2s ease;
  " title="${tooltipText}">
    ${relativeText}
  </div>
`;

/**
 * Pipeline Stats Filter Block
 *
 * Button+Badge clickable filters for the target opportunity list block.
 * Table: nb_crm_opportunities
 */

const TARGET_BLOCK_UID = 'c02af2d19b9';

const { useState, useEffect } = ctx.React;
const { Button, Badge, Space, Spin } = ctx.antd;

const t = (key, opts) => ctx.t(key, { ns: 'nb_crm.pipeline', ...opts });

// ==================== Stat Buttons Config ====================
const getMonthEnd = () => new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0, 23, 59, 59).toISOString();

const STATS = [
  { key: 'all', label: t('All Opportunities'), filter: null },
  { key: 'pipeline', label: t('In Pipeline'),
    filter: { stage: { $notIn: ['won', 'lost'] } } },
  { key: 'closing', label: t('Closing Soon'),
    filter: { $and: [
      { stage: { $notIn: ['won', 'lost'] } },
      { expected_close_date: { $lte: getMonthEnd() } },
    ] } },
  { key: 'won', label: t('Won'), filter: { stage: 'won' } },
  { key: 'lost', label: t('Lost'), filter: { stage: 'lost' } },
];

// ==================== Data Hook ====================
function useStats() {
  const [counts, setCounts] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const results = await Promise.all(
          STATS.map(s => ctx.api.request({
            url: 'nb_crm_opportunities:list',
            params: { pageSize: 1, ...(s.filter && { filter: JSON.stringify(s.filter) }) },
          }))
        );
        const c = {};
        STATS.forEach((s, i) => { c[s.key] = results[i]?.data?.meta?.count || 0; });
        setCounts(c);
      } catch (e) { console.error('Stats fetch failed:', e); }
      setLoading(false);
    };
    fetch();
  }, []);

  return { counts, loading };
}

// ==================== Main Component ====================
const StatsFilter = () => {
  const { counts, loading } = useStats();
  const [active, setActive] = useState('all');

  const handleClick = async (stat) => {
    setActive(stat.key);
    try {
      const target = ctx.engine?.getModel(TARGET_BLOCK_UID);
      if (!target) { ctx.message?.warning('Target block not found'); return; }
      target.resource.addFilterGroup(ctx.model.uid, stat.filter || { $and: [] });
      await target.resource.refresh();
    } catch (e) { console.error('Filter failed:', e); }
  };

  if (loading) return <Spin size="small" />;

  return (
    <Space wrap size={[8, 8]}>
      {STATS.map(s => (
        <Button key={s.key} type={active === s.key ? 'primary' : 'default'} onClick={() => handleClick(s)}>
          {s.label}{' '}
          <Badge count={counts[s.key] ?? 0} showZero overflowCount={9999}
            style={{ marginLeft: 4,
              backgroundColor: active === s.key ? '#fff' : '#f0f0f0',
              color: active === s.key ? '#1677ff' : 'rgba(0,0,0,0.65)',
              boxShadow: 'none' }} />
        </Button>
      ))}
    </Space>
  );
};

ctx.render(<StatsFilter />);
